// payments/payment_service.dart
import 'dart:io';
import 'package:flutter_stripe/flutter_stripe.dart';
import 'package:flutter_dotenv/flutter_dotenv.dart';
import 'package:http/http.dart' as http;
import 'dart:convert';
import '../utils/secure_storage_service.dart';

class PaymentService {
  PaymentService._();
  static final PaymentService instance = PaymentService._();

  Future<void> init() async {
    Stripe.publishableKey = dotenv.env['STRIPE_PUBLISHABLE_KEY']!;
    Stripe.merchantIdentifier = dotenv.env['APPLE_MERCHANT_ID']!;
    await Stripe.instance.applySettings();
  }

  Future<void> payWithCard({
    required int amount,
    required String currency,
    required String description,
  }) async {
    final paymentMethod = await Stripe.instance.createPaymentMethod(
      params: const PaymentMethodParams.card(
        paymentMethodData: PaymentMethodData(),
      ),
    );
    final paymentIntentData = await _createIntent(amount, currency, description);
    await _confirmPayment(paymentIntentData, paymentMethod.id);
  }

  Future<void> payWithWallet({
    required int amount,
    required String currency,
    required String description,
  }) async {
    final paymentItems = [
      PaymentItem(
        label: description,
        amount: (amount / 100).toStringAsFixed(2),
        status: PaymentItemStatus.final_price,
      ),
    ];
    await Stripe.instance.initPaymentSheet(
      paymentSheetParameters: SetupPaymentSheetParameters(
        paymentIntentClientSecret:
            (await _createIntent(amount, currency, description))['client_secret'],
        applePay: PaymentSheetApplePay(
          merchantCountryCode: 'US',
        ),
        googlePay: PaymentSheetGooglePay(
          merchantCountryCode: 'US',
          testEnv: true,
        ),
        style: ThemeMode.dark,
        merchantDisplayName: 'Your Company',
      ),
    );
    await Stripe.instance.presentPaymentSheet();
  }

  Future<Map<String, dynamic>> _createIntent(
      int amount, String currency, String description) async {
    final url = Uri.parse('${dotenv.env['BACKEND_URL']}/create-payment-intent');
    final response = await http.post(
      url,
      headers: {'Content-Type': 'application/json'},
      body: jsonEncode(
        {'amount': amount, 'currency': currency, 'description': description},
      ),
    );
    if (response.statusCode != 200) {
      throw Exception('Failed to create PaymentIntent');
    }
    return jsonDecode(response.body);
  }

  Future<void> _confirmPayment(
      Map<String, dynamic> intentData, String paymentMethodId) async {
    await Stripe.instance.confirmPayment(
      intentData['client_secret'],
      PaymentMethodParams.cardFromMethodId(
        paymentMethodData: PaymentMethodDataCardFromMethod(
          paymentMethodId: paymentMethodId,
        ),
      ),
    );
  }
}

// purchases/in_app_purchase_manager.dart
import 'dart:async';
import 'package:in_app_purchase/in_app_purchase.dart';

class InAppPurchaseManager {
  InAppPurchaseManager._();
  static final InAppPurchaseManager instance = InAppPurchaseManager._();
  final InAppPurchase _iap = InAppPurchase.instance;
  late StreamSubscription<List<PurchaseDetails>> _subscription;

  Future<void> init() async {
    final isAvailable = await _iap.isAvailable();
    if (!isAvailable) return;
    _subscription = _iap.purchaseStream.listen(
      _onPurchaseUpdated,
      onDone: () => _subscription.cancel(),
      onError: (_) {},
    );
  }

  Future<void> buyProduct(String productId) async {
    final ProductDetailsResponse response =
        await _iap.queryProductDetails({productId});
    if (response.notFoundIDs.isNotEmpty) return;
    final ProductDetails productDetails = response.productDetails.first;
    final PurchaseParam purchaseParam = PurchaseParam(
      productDetails: productDetails,
    );
    await _iap.buyConsumable(purchaseParam: purchaseParam);
  }

  void _onPurchaseUpdated(List<PurchaseDetails> purchases) {
    for (final purchase in purchases) {
      if (purchase.status == PurchaseStatus.purchased) {
        _verifyAndComplete(purchase);
      } else if (purchase.status == PurchaseStatus.error) {
        _handleError(purchase.error!);
      }
    }
  }

  Future<void> _verifyAndComplete(PurchaseDetails purchase) async {
    // Server-side receipt validation logic here
    if (purchase.pendingCompletePurchase) {
      await _iap.completePurchase(purchase);
    }
  }

  void _handleError(IAPError error) {
    // Log and display error
  }
}

// utils/secure_storage_service.dart
import 'package:flutter_secure_storage/flutter_secure_storage.dart';

class SecureStorageService {
  SecureStorageService._();
  static final SecureStorageService instance = SecureStorageService._();
  final _storage = const FlutterSecureStorage();

  Future<void> save(String key, String value) async {
    await _storage.write(key: key, value: value);
  }

  Future<String?> read(String key) async {
    return _storage.read(key: key);
  }

  Future<void> delete(String key) async {
    await _storage.delete(key: key);
  }
}

